package dev.codedefense.application;import dev.codedefense.cli.ExitCodes;import dev.codedefense.passport.*;import java.io.PrintWriter;import java.nio.file.Path;import java.util.Objects;
public final class InspectChangeHandoffUseCase {private final ChangeHandoffFileStore store;private final ChangeHandoffJsonCodec codec;private final ChangeHandoffTerminalRenderer renderer;public InspectChangeHandoffUseCase(ChangeHandoffFileStore s,ChangeHandoffJsonCodec c,ChangeHandoffTerminalRenderer r){store=Objects.requireNonNull(s);codec=Objects.requireNonNull(c);renderer=Objects.requireNonNull(r);}public int inspect(Path input,PrintWriter out,PrintWriter err){renderer.render(codec.decode(store.read(input)),out);return ExitCodes.SUCCESS;}}
